pseudocode.cropQtdColumnStrip:
async function cropQtdColumnStrip(tableCropDataUrl, imageWidth?) {
  const image = await decodeImage(tableCropDataUrl);
  const w = image.width;
  const x0 = Math.floor(w * EMPORIO_QTD_X_FRAC.x0); // 438/724
  const x1 = Math.ceil(w * EMPORIO_QTD_X_FRAC.x1);   // 478/724
  if (x1 - x0 < 24) return null; // strip too narrow
  const strip = image.crop(x0, 0, x1 - x0, image.height);
  if (isMostlyBlank(strip)) return null;
  return await encodeDataUrl(strip);
}

pseudocode.runQuantityPrePass:
async function runQuantityPrePass(tableCropDataUrl, apiKey, opts?) {
  const qtdStripUrl = await cropQtdColumnStrip(tableCropDataUrl);
  const useStrip = qtdStripUrl != null;
  const imageUrl = useStrip ? qtdStripUrl : tableCropDataUrl;
  const systemPrompt = useStrip ? QTD_STRIP_SYSTEM_PROMPT : QTY_PREPAS_SYSTEM_PROMPT;
  const userText = useStrip
    ? 'Read decimal quantity from each horizontal row band. Top-to-bottom order. Qtd column only.'
    : 'Copy quantity and unit from the Qtd column for each visible invoice line item.';
  const parsed = await callOpenAiJson(apiKey, [{ role: 'system', content: systemPrompt }, { role: 'user', content: [{ type: 'text', text: userText }, { type: 'image_url', image_url: { url: imageUrl } }] }], QTY_PREPAS_RESPONSE_FORMAT);
  return normalizePrepassRows(parsed.items, { stripMode: useStrip });
}

pseudocode.normalizePrepassRows:
function normalizePrepassRows(raw, { stripMode }) {
  return raw.map((item, i) => ({
    name: stripMode ? `row-${i}` : (item.name ?? 'Unknown item'),
    quantity: typeof item.quantity === 'number' ? item.quantity : null,
    unit: stripMode ? 'kg' : (item.unit ?? null), // Emporio deli default; Pass C overrides
  }));
}

